    def _encode_with_positions(
        self, text: str, allowed_special: AbstractSet[str]
    ) -> tuple[list[int], list[int]]:
        """Encodes text into tokens, tracking the starting character position of each token.

        Special tokens in `allowed_special` are matched as whole tokens; everything else is
        regex-split and BPE-encoded piece by piece, same as the normal encode path.
        """
        tokens: list[int] = []
        positions: list[int] = []

        if allowed_special:
            matches = list(_special_token_regex(frozenset(allowed_special)).finditer(text))
        else:
            matches = []

        last_end = 0
        for match in matches:
            if match.start() > last_end:
                self._encode_ordinary_with_positions(
                    text[last_end : match.start()], last_end, tokens, positions
                )
            positions.append(match.start())
            tokens.append(self.encode_single_token(match.group()))
            last_end = match.end()
        if last_end < len(text):
            self._encode_ordinary_with_positions(text[last_end:], last_end, tokens, positions)

        return tokens, positions

    def _encode_ordinary_with_positions(
        self, text: str, offset: int, tokens: list[int], positions: list[int]
    ) -> None:
        """Encodes non-special text, appending tokens and their positions (relative to the
        original input via `offset`) to the given lists in place."""
